CREATE OR REPLACE FUNCTION fpb_get_keep_month_int_return (as_memno char ,as_conno char , as_receiptno char) RETURNS bigint AS $body$
DECLARE

ldc_amount  bigint;

BEGIN
      select sum(sc_kep_t_monthly_receive_det.return_interest)
      into STRICT   ldc_amount
			from 	sc_kep_t_monthly_receive,sc_kep_t_monthly_receive_det
			where	sc_kep_t_monthly_receive.receive_year = sc_kep_t_monthly_receive_det.receive_year
			and		sc_kep_t_monthly_receive.receive_month = sc_kep_t_monthly_receive_det.receive_month
			and		sc_kep_t_monthly_receive.membership_no = sc_kep_t_monthly_receive_det.membership_no
			and		sc_kep_t_monthly_receive.membership_no = as_memno
			and		sc_kep_t_monthly_receive.receipt_no = as_receiptno
      and   trim(both sc_kep_t_monthly_receive_det.receive_description) = trim(both as_conno)
;

    return ldc_amount;
  exception when others then return 0;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
